files.patch:
@@ -0,0 +1,15 @@
+{
+  "name": "cnl_cpl_combined",
+  "description": "CNL moves cursor N lines down to col 0; CPL moves N lines up to col 0",
+  "initial_size": [5, 5],
+  "input_bytes_hex": "1b5b333b3348411b5b3245421b5b334643",
+  "comment": "CUP(3,3) → (2,2), print A; CNL(2) → (4,0), print B; CPL(3) → (1,0), print C; cursor at (1,1)",
+  "expected": {
+    "cursor": { "row": 1, "col": 1 },
+    "cells": [
+      { "row": 2, "col": 2, "char": "A" },
+      { "row": 4, "col": 0, "char": "B" },
+      { "row": 1, "col": 0, "char": "C" }
+    ]
+  }
+}

@@ -0,0 +1,13 @@
+{
+  "name": "vpa_cha_combo",
+  "description": "VPA (cursor row) and CHA (cursor column) used together for absolute positioning",
+  "initial_size": [10, 5],
+  "input_bytes_hex": "1b5b33641b5b344758",
+  "comment": "VPA(3) → row 2; CHA(4) → col 3; print X at (2,3); cursor at (2,4)",
+  "expected": {
+    "cursor": { "row": 2, "col": 4 },
+    "cells": [
+      { "row": 2, "col": 3, "char": "X" }
+    ]
+  }
+}

@@ -0,0 +1,15 @@
+{
+  "name": "index_at_region_bottom",
+  "description": "Index (ESC D) at bottom of scroll region scrolls up within region",
+  "initial_size": [5, 5],
+  "input_bytes_hex": "411b5b323b3148421b5b333b3148431b5b313b33721b5b333b31481b4444",
+  "comment": "Print A(0,0), B(1,0), C(2,0); set region rows 1-3 (0-2); CUP(3,1) → (2,0) bottom of region; ESC D index scrolls: A evicted to scrollback, B→(0,0), C→(1,0), blank at (2,0); print D at (2,0); cursor at (2,1)",
+  "expected": {
+    "cursor": { "row": 2, "col": 1 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "B" },
+      { "row": 1, "col": 0, "char": "C" },
+      { "row": 2, "col": 0, "char": "D" }
+    ]
+  }
+}

@@ -0,0 +1,13 @@
+{
+  "name": "decom_vpa_in_region",
+  "description": "DECOM (origin mode) makes VPA (CSI d) addressing relative to scroll region",
+  "initial_size": [10, 6],
+  "input_bytes_hex": "1b5b323b35721b5b3f36681b5b34471b5b326459",
+  "comment": "CSI 2;5 r (region rows 1-4, 0-based), CSI ? 6 h (DECOM on), CSI 4 G (CHA col 3), CSI 2 d (VPA row=1 relative → abs row 2), print Y at (2,3); cursor at (2,4)",
+  "expected": {
+    "cursor": { "row": 2, "col": 4 },
+    "cells": [
+      { "row": 2, "col": 3, "char": "Y" }
+    ]
+  }
+}

@@ -0,0 +1,13 @@
+{
+  "name": "back_tab_at_origin",
+  "description": "CBT (back tab) from column 0 stays at column 0",
+  "initial_size": [20, 3],
+  "input_bytes_hex": "1b5b5a41",
+  "comment": "CBT(1) from col 0 → stays at col 0 (no prior tab stop); print A at (0,0); cursor at (0,1)",
+  "expected": {
+    "cursor": { "row": 0, "col": 1 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "A" }
+    ]
+  }
+}
